import { User, UserRole, Branch, LandParcel, DashboardStats, SystemLog, LandPriceConfig, WMSLayerConfig, SystemSetting, RoleConfig, PermissionDefinition, BasemapConfig, MenuItem } from '../types';

const getApiUrl = () => {
    const { hostname } = window.location;
    if (hostname === 'localhost' || hostname === '127.0.0.1') {
        return `http://localhost:3004`;
    }
    return 'https://apigeo.gisvn.space'; 
};

export const API_URL = getApiUrl();

const getAuthHeaders = () => {
    const headers: any = {};
    const userStr = localStorage.getItem('geo_user');
    if (userStr) {
        try {
            const u = JSON.parse(userStr);
            headers['x-user-id'] = u.id;
            headers['x-user-name'] = encodeURIComponent(u.name);
            headers['x-branch-id'] = u.branchId || u.branch_id;
        } catch (e) {}
    }
    return headers;
};

const apiCall = async (endpoint: string, options?: RequestInit) => {
    const cleanEndpoint = endpoint.startsWith('/api') ? endpoint : `/api${endpoint}`;
    const finalUrl = `${API_URL}${cleanEndpoint}`;

    try {
        const headers: any = { 'Content-Type': 'application/json', ...getAuthHeaders(), ...options?.headers };

        if (options?.body instanceof FormData) delete headers['Content-Type'];

        const res = await fetch(finalUrl, { ...options, headers });
        const responseText = await res.text();

        let responseData: any = null;
        if (responseText) {
            try { responseData = JSON.parse(responseText); } catch (e) {}
        }

        if (!res.ok) {
            let errorMessage = `Lỗi hệ thống (${res.status})`;
            if (responseData && (responseData.error || responseData.message)) {
                errorMessage = responseData.error || responseData.message;
            }
            if (res.status >= 500) {
                console.error(`[API Error] ${res.status} ${finalUrl}:`, errorMessage);
            } else {
                console.warn(`[API Info] ${res.status} ${finalUrl}:`, errorMessage);
            }
            throw new Error(errorMessage);
        }

        return responseData || { status: 'ok' };
    } catch (error: any) {
        if (error.name === 'TypeError' && error.message === 'Failed to fetch') {
             console.error(`[Network Error] Failed to connect to ${finalUrl}`);
        }
        throw error;
    }
};

const getMenuItems = async (): Promise<MenuItem[]> => await apiCall('/menu-items');
const addMenuItem = async (item: MenuItem) => await apiCall('/menu-items', { method: 'POST', body: JSON.stringify(item) });
const updateMenuItem = async (item: MenuItem) => await apiCall(`/menu-items/${item.id}`, { method: 'PUT', body: JSON.stringify(item) });
const deleteMenuItem = async (id: string) => await apiCall(`/menu-items/${id}`, { method: 'DELETE' });

export const gisService = {
    getLayers: async (): Promise<WMSLayerConfig[]> => {
        try { return await apiCall('/wms-layers'); } catch (e) { return []; }
    },
    getBasemaps: async (): Promise<BasemapConfig[]> => {
        try { return await apiCall('/basemaps'); } catch (e) { return []; }
    },
    getSpatialTables: async (): Promise<any[]> => {
        try { return await apiCall('/spatial-tables'); } catch (e) { return []; }
    },
    searchParcels: async (tableName: string, filters: { sodoto?: string, sothua?: string, tenchu?: string, diachi?: string }): Promise<LandParcel[]> => {
        try {
             let queryString = `?t=${Date.now()}`;
             if (filters.sodoto) queryString += `&sodoto=${encodeURIComponent(filters.sodoto)}`;
             if (filters.sothua) queryString += `&sothua=${encodeURIComponent(filters.sothua)}`;
             if (filters.tenchu) queryString += `&tenchu=${encodeURIComponent(filters.tenchu)}`;
             if (filters.diachi) queryString += `&diachi=${encodeURIComponent(filters.diachi)}`;
             const data = await apiCall(`/data/${tableName}${queryString}`);
             if (!Array.isArray(data)) return [];
             return data.map((item: any) => ({
                 id: item.gid?.toString() || `p-${Math.random()}`,
                 gid: item.gid,
                 geometry: item.geometry,
                 properties: { ...item, so_to: item.sodoto, so_thua: item.sothua, ownerName: item.tenchu, address: item.diachi, area: item.dientich, landType: item.loaidat || item.kyhieumucd || 'Chưa cập nhật', tableName: tableName }
             }));
        } catch (e) { return []; }
    }
};

