const getApiUrl = () => {
    const { hostname, protocol } = window.location;
    const isLocal = 
        hostname === 'localhost' || 
        hostname === '127.0.0.1' || 
        hostname.startsWith('192.168.') || 
        hostname.startsWith('10.') || 
        hostname.startsWith('172.');

    if (isLocal) {
        return `${protocol}//${hostname}:3004`;
    }
    return 'https://apigeo.gisvn.space'; 
};

export const API_URL = getApiUrl();

export interface ParcelDTO {
    gid?: number; 
    sothua: string;
    sodoto: string;
    tenchu?: string;
    diachi?: string;
    loaidat?: string; 
    dientich?: number;
    geometry?: any; 
    file?: File | null; 
    [key: string]: any; 
}

export interface SpatialTable {
    table_name: string;
    display_name: string;
    description?: string;
}

const getAuthHeaders = () => {
    const headers: any = { 'Content-Type': 'application/json' };
    const userStr = localStorage.getItem('geo_user');
    if (userStr) {
        try {
            const u = JSON.parse(userStr);
            headers['x-user-id'] = u.id;
            headers['x-user-name'] = encodeURIComponent(u.name);
            headers['x-branch-id'] = u.branchId || u.branch_id;
        } catch (e) {}
    }
    return headers;
};

const handleResponse = async (res: Response) => {
    const responseText = await res.text();
    let responseData: any = null;
    if (responseText) {
        try { responseData = JSON.parse(responseText); } catch (e) {}
    }
    if (!res.ok) {
        let message = `Lỗi API (${res.status})`;
        if (responseData && (responseData.error || responseData.message)) {
            message = responseData.error || responseData.message;
        }
        throw new Error(message);
    }
    return responseData || { status: 'ok' };
};

export const parcelApi = {
    getAll: async (layer: string, filters?: { sodoto?: string, sothua?: string, tenchu?: string, diachi?: string }) => {
        let queryString = `?t=${Date.now()}`;
        if (filters) {
            if (filters.sodoto) queryString += `&sodoto=${encodeURIComponent(filters.sodoto)}`;
            if (filters.sothua) queryString += `&sothua=${encodeURIComponent(filters.sothua)}`;
            if (filters.tenchu) queryString += `&tenchu=${encodeURIComponent(filters.tenchu)}`;
            if (filters.diachi) queryString += `&diachi=${encodeURIComponent(filters.diachi)}`;
        }
        const res = await fetch(`${API_URL}/api/data/${layer}${queryString}`, { headers: { ...getAuthHeaders() } });
        return await handleResponse(res);
    },

    create: async (layer: string, data: ParcelDTO) => {
        const res = await fetch(`${API_URL}/api/data/${layer}`, { method: 'POST', headers: { ...getAuthHeaders() }, body: JSON.stringify(data) });
        return await handleResponse(res);
    },

    createWithUpload: async (layer: string, data: ParcelDTO) => {
        const formData = new FormData();
        Object.keys(data).forEach(key => {
            if (key === 'file' && data[key]) formData.append('file', data[key] as File);
            else if (data[key] !== undefined && data[key] !== null) formData.append(key, String(data[key]));
        });
        const headers = { ...getAuthHeaders() };
        delete headers['Content-Type'];
        const res = await fetch(`${API_URL}/api/data/${layer}/upload`, { method: 'POST', headers, body: formData });
        return await handleResponse(res);
    },

    update: async (layer: string, gid: number, data: ParcelDTO) => {
        const res = await fetch(`${API_URL}/api/data/${layer}/${gid}`, { method: 'PUT', headers: { ...getAuthHeaders() }, body: JSON.stringify(data) });
        return await handleResponse(res);
    },

    updateGeometry: async (layer: string, gid: number, geometry: any, area: number) => {
        const res = await fetch(`${API_URL}/api/data/${layer}/${gid}/geometry`, { method: 'PUT', headers: { ...getAuthHeaders() }, body: JSON.stringify({ geometry, area }) });
        return await handleResponse(res);
    },

    delete: async (layer: string, gid: number) => {
        const res = await fetch(`${API_URL}/api/data/${layer}/${gid}`, { method: 'DELETE', headers: { ...getAuthHeaders() } });
        return await handleResponse(res);
    },

    manageTables: {
        getAll: async (): Promise<SpatialTable[]> => {
            const res = await fetch(`${API_URL}/api/spatial-tables?t=${Date.now()}`, { headers: { ...getAuthHeaders() } });
            return await handleResponse(res);
        },
        create: async (tableName: string, displayName?: string, description?: string) => {
            const name = (tableName || '').toLowerCase().trim();
            const res = await fetch(`${API_URL}/api/spatial-tables`, {
                method: 'POST',
                headers: { ...getAuthHeaders() },
                body: JSON.stringify({ tableName: name, displayName, description })
            });
            return await handleResponse(res);
        },
        link: async (tableName: string, displayName?: string, description?: string) => {
            const name = (tableName || '').toLowerCase().trim();
            const res = await fetch(`${API_URL}/api/spatial-tables/link`, {
                method: 'POST',
                headers: { ...getAuthHeaders() },
                body: JSON.stringify({ tableName: name, displayName, description })
            });
            return await handleResponse(res);
        },
        rename: async (oldName: string, newName: string, displayName: string, description?: string) => {
            const res = await fetch(`${API_URL}/api/spatial-tables/rename`, {
                method: 'POST',
                headers: { ...getAuthHeaders() },
                body: JSON.stringify({ oldName, newName, displayName, description })
            });
            return await handleResponse(res);
        },
        unlink: async (tableName: string) => {
            const name = (tableName || '').toLowerCase().trim();
            const res = await fetch(`${API_URL}/api/spatial-tables/unlink`, { 
                method: 'POST', 
                headers: { ...getAuthHeaders() }, 
                body: JSON.stringify({ tableName: name, table_name: name }) 
            });
            return await handleResponse(res);
        },
        delete: async (tableName: string) => {
            const name = (tableName || '').toLowerCase().trim();
            const res = await fetch(`${API_URL}/api/spatial-tables/${name}`, { method: 'DELETE', headers: { ...getAuthHeaders() } });
            return await handleResponse(res);
        }
    }
};

import React, { useState, useEffect } from 'react';
import { User, UserRole, MenuItem } from '../types';
import { LogOut, LogIn, ChevronLeft, ChevronRight, User as UserIcon, Database, HelpCircle, ExternalLink } from 'lucide-react';
import * as Icons from 'lucide-react';
import { adminService, API_URL } from '../services/mockBackend';

interface SidebarProps {
  user: User | null;
  activePage: string;
  onNavigate: (page: string) => void;
  onLogout: () => void;
  onLoginClick: () => void;
  onCollapse: () => void;
  isCollapsed: boolean;
  systemName?: string;
  logoUrl?: string;
}

const Sidebar: React.FC<SidebarProps> = ({ 
    user, 
    activePage, 
    onNavigate, 
    onLogout, 
    onLoginClick, 
    onCollapse, 
    isCollapsed,
    systemName, 
    logoUrl 
}) => {
  const [dynamicMenu, setDynamicMenu] = useState<MenuItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [imgError, setImgError] = useState(false);

  useEffect(() => {
      setImgError(false);
  }, [user?.avatar, user?.id]);

  useEffect(() => {
      const fetchMenu = async () => {
          try {
              if (adminService && typeof adminService.getMenuItems === 'function') {
                  const items = await adminService.getMenuItems();
                  setDynamicMenu(items.filter(i => i.is_active).sort((a, b) => a.order_index - b.order_index));
              }
          } catch (e) {
              console.error("Failed to load sidebar menu", e);
          } finally {
              setLoading(false);
          }
      };
      fetchMenu();
  }, [user?.role]);

  const visibleItems = dynamicMenu.filter(item => {
    if (!user) return item.roles.includes('GUEST');
    return item.roles.includes(user.role);
  });

  const handleMenuClick = (item: MenuItem) => {
      if (item.type === 'EXTERNAL' && item.url) {
          window.open(item.url, '_blank');
      } else {
          onNavigate(item.id);
      }
  };

  const getAvatarUrl = (path?: string) => {
      if (!path) return null;
      if (path.startsWith('http') || path.startsWith('data:')) return path;

      const cleanPath = path.startsWith('/') ? path : `/${path}`;
      const baseUrl = API_URL.endsWith('/') ? API_URL.slice(0, -1) : API_URL;

      // Thêm timestamp để ép trình duyệt di động tải lại ảnh mới thay vì dùng cache lỗi
      return `${baseUrl}${cleanPath}?v=${new Date().getTime()}`;
  };

  const renderAvatar = () => {
      if (!user) return <UserIcon size={18} className="text-blue-400" />;

      const avatarSrc = getAvatarUrl(user.avatar);

      if (avatarSrc && !imgError) {
          return (
              <img 
                  src={avatarSrc} 
                  alt={user.name} 
                  className="w-full h-full object-cover" 
                  onError={(e) => {
                      console.error("[Avatar Error] Failed to load URL:", avatarSrc);
                      setImgError(true);
                  }}
              />
          );
      }

      return (
          <div className="w-full h-full bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center text-white font-bold text-xs uppercase">
              {user.name ? user.name.charAt(0) : <UserIcon size={16} />}
          </div>
      );
  };

  return (
    <div className={`${isCollapsed ? 'w-20' : 'w-72'} bg-[#0f172a] text-white h-screen flex flex-col transition-all duration-300 ease-in-out border-r border-slate-800 relative z-50 shadow-2xl`}>
      <button 
        onClick={onCollapse} 
        className="absolute -right-3 top-10 bg-blue-600 text-white rounded-full p-1.5 shadow-lg border-2 border-[#0f172a] hover:bg-blue-500 transition-all z-[60]"
      >
        {isCollapsed ? <ChevronRight size={14} /> : <ChevronLeft size={14} />}
      </button>

      <div className={`p-6 border-b border-slate-800/80 flex flex-col items-center ${isCollapsed ? 'justify-center' : 'items-start'}`}>
        <div className="flex items-center gap-3.5">
            {logoUrl ? (
                <img src={logoUrl} alt="Logo" className="w-9 h-9 object-contain drop-shadow-[0_0_15px_rgba(59,130,246,0.6)]" />
            ) : (
                <div className="w-9 h-9 bg-blue-600 rounded-lg flex items-center justify-center shadow-lg shadow-blue-900/50">
                    <Database className="w-5 h-5 text-white" />
                </div>
            )}
            {!isCollapsed && (
                <div className="animate-in fade-in slide-in-from-left-2 duration-300">
                    <h1 className="text-base font-black text-white leading-none uppercase tracking-tighter mb-1">
                        {systemName || 'GeoMaster'}
                    </h1>
                    <div className="flex items-center gap-1.5">
                        <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
                        <p className="text-[9px] text-slate-400 font-bold tracking-[0.2em] uppercase">Enterprise</p>
                    </div>
                </div>
            )}
        </div>
      </div>

      <div className="flex-1 py-6 space-y-1.5 overflow-y-auto custom-scrollbar no-scrollbar px-3">
        {loading ? (
            <div className="animate-pulse flex flex-col gap-3 px-2">
                {[1,2,3].map(i => <div key={i} className="h-11 bg-slate-800/50 rounded-xl w-full"></div>)}
            </div>
        ) : visibleItems.map(item => {
          const isActive = activePage === item.id;
          const IconComponent = (Icons as any)[item.icon] || HelpCircle;

          return (
            <button
              key={item.id}
              onClick={() => handleMenuClick(item)}
              title={isCollapsed ? item.label : ''}
              className={`w-full flex items-center gap-3.5 px-4 py-3 rounded-xl transition-all relative group overflow-hidden ${
                isActive 
                  ? 'text-white bg-blue-600 shadow-lg shadow-blue-900/20' 
                  : 'text-slate-400 hover:text-white hover:bg-slate-800/80'
              }`}
            >
              <div className={`${isCollapsed ? 'mx-auto' : ''} transition-transform group-hover:scale-110 flex items-center z-10`}>
                <IconComponent size={20} className={isActive ? 'text-white' : 'text-slate-400 group-hover:text-blue-400'} />
              </div>

              {!isCollapsed && (
                <div className="flex-1 flex items-center justify-between animate-in fade-in slide-in-from-left-2 duration-300 z-10">
                    <span className={`font-bold text-xs uppercase tracking-wide ${isActive ? 'text-white' : ''}`}>
                        {item.label}
                    </span>
                    {item.type === 'EXTERNAL' && (
