import express from 'express';

export default function(pool) {
    const router = express.Router();

    router.get('/dashboard', async (req, res) => {
        try {
            // Lấy tổng số thửa và diện tích từ tất cả các bảng đã đăng ký trong registry
            const registryRes = await pool.query('SELECT table_name FROM spatial_tables_registry');
            const tables = registryRes.rows;

            let totalParcels = 0;
            let totalArea = 0;

            if (tables.length > 0) {
                // Query tổng hợp nhanh (chỉ mang tính minh họa, thực tế nên dùng view hoặc cache)
                for (const t of tables) {
                    const countRes = await pool.query(`SELECT COUNT(*) as count, SUM(COALESCE(dientich, 0)) as area FROM "${t.table_name}"`);
                    totalParcels += parseInt(countRes.rows[0].count);
                    totalArea += parseFloat(countRes.rows[0].area || 0);
                }
            }

            // Mock data cho các biểu đồ nếu DB chưa có đủ dữ liệu phân loại
            res.json({
                totalParcels,
                totalArea,
                totalValue: totalArea * 500000, // Giá tạm tính
                parcelsByType: [
                    { name: 'Đất ở', value: Math.round(totalParcels * 0.4) },
                    { name: 'Đất nông nghiệp', value: Math.round(totalParcels * 0.6) }
                ],
                valueByBranch: [
                    { name: 'Khu vực 1', value: Math.round(totalParcels * 0.5) },
                    { name: 'Khu vực 2', value: Math.round(totalParcels * 0.5) }
                ]
            });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });

    return router;
}

